changeSet.sql:
WITH duplicate_pillars AS ( SELECT owner_id, LOWER(code) AS normalized_code, MIN(id) AS kept_id FROM pillar WHERE owner_id IS NOT NULL GROUP BY owner_id, LOWER(code) HAVING COUNT(*) > 1 ) UPDATE pillar_translation pt SET pillar_id = dp.kept_id FROM pillar p JOIN duplicate_pillars dp ON p.owner_id = dp.owner_id AND LOWER(p.code) = dp.normalized_code WHERE pt.pillar_id = p.id AND p.id <> dp.kept_id;
WITH duplicate_pillars AS ( SELECT owner_id, LOWER(code) AS normalized_code, MIN(id) AS kept_id FROM pillar WHERE owner_id IS NOT NULL GROUP BY owner_id, LOWER(code) HAVING COUNT(*) > 1 ) UPDATE sub_pillar sp SET pillar_id = dp.kept_id FROM pillar p JOIN duplicate_pillars dp ON p.owner_id = dp.owner_id AND LOWER(p.code) = dp.normalized_code WHERE sp.pillar_id = p.id AND p.id <> dp.kept_id;
DELETE FROM pillar_translation WHERE id IN ( SELECT pt.id FROM pillar_translation pt JOIN ( SELECT pillar_id, lang, MIN(id) AS kept_id FROM pillar_translation GROUP BY pillar_id, lang HAVING COUNT(*) > 1 ) duplicates ON duplicates.pillar_id = pt.pillar_id AND duplicates.lang = pt.lang WHERE pt.id <> duplicates.kept_id );
DELETE FROM pillar WHERE id IN ( SELECT p.id FROM pillar p JOIN ( SELECT owner_id, LOWER(code) AS normalized_code, MIN(id) AS kept_id FROM pillar WHERE owner_id IS NOT NULL GROUP BY owner_id, LOWER(code) HAVING COUNT(*) > 1 ) duplicates ON duplicates.owner_id = p.owner_id AND duplicates.normalized_code = LOWER(p.code) WHERE p.id <> duplicates.kept_id );
